```aether:src/db.ts
import { Task, User, Team } from './types';

// --- Mock Database ---
const tasks: Task[] = [];
const users: User[] = [
  { id: 'user-1', teamId: 'team-a' },
  { id: 'user-2', teamId: 'team-a' },
  { id: 'user-3', teamId: 'team-b' },
];
const teams: Team[] = [
  { id: 'team-a', name: 'Alpha Team' },
  { id: 'team-b', name: 'Beta Team' },
];

let taskIdCounter = 1;

export const db = {
  tasks,
  users,
  teams,

  insertTask: (taskData: Omit<Task, 'id'>): Task => {
    const newTask: Task = {
      id: `task-${taskIdCounter++}`,
      ...taskData,
    };
    tasks.push(newTask);
    return newTask;
  },

  findUserById: (userId: string): User | undefined => {
    return users.find(u => u.id === userId);
  },

  findTeamById: (teamId: string): Team | undefined => {
    return teams.find(t => t.id === teamId);
  }
};
