```aether:src/middleware/auth.ts
import { Context, Next } from 'hono';
import { db } from '../db';

// Extend Hono's Context to include our custom properties
declare module 'hono' {
  interface ContextVariableMap {
    userId: string;
    teamId: string;
  }
}

/**
 * Mock authentication middleware.
 * In a real application, this would validate a token,
 * fetch user details, and set `userId` and `teamId` based on the authenticated user.
 * For this exercise, we'll hardcode a user.
 */
export const authMiddleware = async (c: Context, next: Next) => {
  // Simulate an authenticated user (e.g., from a JWT token)
  const authenticatedUserId = 'user-1'; // This user belongs to 'team-a'

  const user = db.findUserById(authenticatedUserId);

  if (!user) {
    return c.json({ error: 'Unauthorized: User not found' }, 401);
  }

  // Set user and team ID in the context for downstream handlers
  c.set('userId', user.id);
  c.set('teamId', user.teamId);

  await next();
};
