```aether:src/routes/tasks/create.ts
import { Hono } from 'hono';
import { z } from 'zod';
import { db } from '../../db';

const createTaskSchema = z.object({
  title: z.string({
    required_error: 'Title is required',
  }).min(1, 'Title cannot be empty'),
  description: z.string().optional(),
  assigneeId: z.string({
    required_error: 'Assignee ID is required',
  }).min(1, 'Assignee ID cannot be empty'),
});

export const createTaskRoute = new Hono();

createTaskRoute.post('/', async (c) => {
  const teamId = c.get('teamId'); // Retrieved from auth middleware

  try {
    const body = await c.req.json();
    const validatedData = createTaskSchema.parse(body);

    // Validate assigneeId belongs to the same team
    const assignee = db.findUserById(validatedData.assigneeId);
    if (!assignee || assignee.teamId !== teamId) {
      return c.json({ error: 'Assignee not found or does not belong to your team' }, 400);
    }

    const newTask = db.insertTask({
      title: validatedData.title,
      description: validatedData.description,
      assigneeId: validatedData.assigneeId,
      teamId: teamId, // Enforce the invariant: task belongs to the caller's team
    });

    return c.json(newTask, 201);
  } catch (error: any) {
    if (error instanceof z.ZodError) {
      return c.json({ errors: error.errors }, 400);
    }
    console.error('Error creating task:', error);
    return c.json({ error: 'Internal server error' }, 500);
  }
});
