```aether:src/index.ts
import { Hono } from 'hono';
import { logger } from 'hono/logger';
import { prettyJSON } from 'hono/pretty-json';
import { authMiddleware } from './middleware/auth';
import { createTaskRoute } from './routes/tasks/create';

const app = new Hono();

// Middlewares
app.use(logger()); // Logs requests to the console
app.use(prettyJSON()); // Formats JSON responses nicely

// Apply authentication middleware to all routes under /tasks
app.use('/tasks/*', authMiddleware);

// Mount task routes
app.route('/tasks', createTaskRoute);

// Basic health check route
app.get('/', (c) => {
  return c.json({ message: 'Aether Task API is running!' });
});

// Error handling for unmatched routes
app.notFound((c) => {
  return c.json({ message: 'Not Found', ok: false }, 404);
});

// Global error handler
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ error: 'An unexpected error occurred' }, 500);
});

export default app;
```

